// Ported from https://github.com/buttons/vue-github-button/blob/main/index.js

import { defineComponent, h } from 'vue'
import { hasOwn, hyphenate } from '@vue/shared'

export default defineComponent({
  name: 'GithubButton',
  props: {
    href: String,
    ariaLabel: String,
    title: String,
    dataIcon: String,
    dataColorScheme: String,
    dataSize: String,
    dataShowCount: String,
    dataText: String,
  },
  mounted: function () {
    this.paint()
  },
  beforeUpdate: function () {
    this.reset()
  },
  updated: function () {
    this.paint()
  },
  beforeUnmount: function () {
    this.reset()
  },
  methods: {
    paint: function () {
      const _ = this.$el.appendChild(document.createElement('span'))
      const _this = this
      import('github-buttons').then(function (module) {
        module.render(_.appendChild(_this.$refs._), function (el) {
          try {
            _.parentNode.replaceChild(el, _)
          } catch (_) {}
        })
      })
    },
    reset: function () {
      this.$el.replaceChild(/** @type {HTMLAnchorElement} */ (this.$refs._), this.$el.lastChild)
    },
  },
  render: function () {
    const props = { ref: '_' }
    for (const key in this.$props) {
      props[hyphenate(key)] = this.$props[key]
    }
    return h('span', [
      hasOwn(this.$slots, 'default')
        ? h('a', props, this.$slots.default())
        : h('a', props),
    ])
  },
})

import { extend } from '../../vue'
import { NAME_TABLE_SIMPLE } from '../../constants/components'
import { sortKeys } from '../../utils/object'
import { makePropsConfigurable } from '../../utils/props'
import { attrsMixin } from '../../mixins/attrs'
import { hasListenerMixin } from '../../mixins/has-listener'
import { idMixin, props as idProps } from '../../mixins/id'
import { normalizeSlotMixin } from '../../mixins/normalize-slot'
import { stackedMixin, props as stackedProps } from './helpers/mixin-stacked'
import { tableRendererMixin, props as tableRendererProps } from './helpers/mixin-table-renderer'

// --- Props ---

export const props = makePropsConfigurable(
  sortKeys({
    ...idProps,
    ...stackedProps,
    ...tableRendererProps
  }),
  NAME_TABLE_SIMPLE
)

// --- Main component ---

// @vue/component
export const BTableSimple = /*#__PURE__*/ extend({
  name: NAME_TABLE_SIMPLE,
  // Order of mixins is important!
  // They are merged from first to last, followed by this component
  mixins: [
    // General mixins
    attrsMixin,
    hasListenerMixin,
    idMixin,
    normalizeSlotMixin,
    // Required table mixins
    tableRendererMixin,
    // Table features mixins
    // Stacked requires extra handling by users via
    // the table cell `stacked-heading` prop
    stackedMixin
  ],
  props,
  computed: {
    isTableSimple() {
      return true
    }
  }
  // Render function is provided by `tableRendererMixin`
})

import { extend, mergeData } from '../../vue'
import { NAME_CARD_IMG_LAZY } from '../../constants/components'
import { keys, omit, sortKeys } from '../../utils/object'
import { makePropsConfigurable } from '../../utils/props'
import { props as BImgProps } from '../image/img'
import { BImgLazy, props as BImgLazyProps } from '../image/img-lazy'
import { props as BCardImgProps } from './card-img'

// --- Props ---

export const props = makePropsConfigurable(
  sortKeys({
    ...omit(BImgLazyProps, keys(BImgProps)),
    ...omit(BCardImgProps, ['src', 'alt', 'width', 'height'])
  }),
  NAME_CARD_IMG_LAZY
)

// --- Main component ---

// @vue/component
export const BCardImgLazy = /*#__PURE__*/ extend({
  name: NAME_CARD_IMG_LAZY,
  functional: true,
  props,
  render(h, { props, data }) {
    let baseClass = 'card-img'
    if (props.top) {
      baseClass += '-top'
    } else if (props.right || props.end) {
      baseClass += '-right'
    } else if (props.bottom) {
      baseClass += '-bottom'
    } else if (props.left || props.start) {
      baseClass += '-left'
    }

    return h(
      BImgLazy,
      mergeData(data, {
        class: [baseClass],
        // Exclude `left` and `right` props before passing to `<b-img-lazy>`
        props: omit(props, ['left', 'right'])
      })
    )
  }
})

import { extend, mergeData } from '../../vue'
