export const BDropdownForm = /*#__PURE__*/ extend({
  name: NAME_DROPDOWN_FORM,
  functional: true,
  props,
  render(h, { props, data, listeners, children }) {
    return h('li', mergeData(omit(data, ['attrs', 'on']), { attrs: { role: 'presentation' } }), [
